1	use crate::embed::detector::{EmbedDetector, EmbedTarget};
2	use crate::embed::types::{EmbedCandidate, GuestLanguage, HostLanguage};
3	use crate::workspace::DocumentFileSource;
4	use biome_html_syntax::ScriptType;
5	
6	/// Returned by the registry when a detector matches.
7	pub(crate) struct EmbedMatch {
8	    pub guest: GuestLanguage,
9	}
10	
11	pub(crate) struct EmbedDetectorsRegistry;
12	
13	impl EmbedDetectorsRegistry {
14	    /// Look up the detectors for a given host language.
15	    pub const fn detectors(host: HostLanguage) -> &'static [EmbedDetector] {
16	        match host {
17	            HostLanguage::Html => &HTML_DETECTORS,
18	            HostLanguage::JavaScript => &JS_DETECTORS,
19	            HostLanguage::Markdown => &[], // Future: MARKDOWN_DETECTORS
20	        }
21	    }
22	
23	    /// Find the first matching detector for a candidate.
24	    pub fn detect_match(
25	        host: HostLanguage,
26	        candidate: &EmbedCandidate,
27	        file_source: &DocumentFileSource,
28	    ) -> Option<EmbedMatch> {
29	        let detectors = Self::detectors(host);
30	        for detector in detectors {
31	            if let Some(guest) = detector.try_match(candidate, file_source) {
32	                return Some(EmbedMatch { guest });
33	            }
34	        }
35	        None
36	    }
37	}
38	
39	static HTML_DETECTORS: [EmbedDetector; 5] = [
40	    // <script> → JS/TS/JSON (dynamic: depends on type/lang attributes + framework)
41	    //
42	    // A single detector handles all <script> variants via the dynamic resolver:
43	    //   - <script>                               → JsScript (classic HTML)
44	    //   - <script type="module">                 → JsModule (ES module)
45	    //   - <script lang="ts">                     → Ts (Vue/Svelte)
46	    //   - <script lang="tsx">                    → Tsx (Vue/Svelte)
47	    //   - <script lang="jsx">                    → Jsx (Vue/Svelte)
48	    //   - <script type="importmap">              → Json
49	    //   - <script type="application/json">       → Json
50	    //   - Astro <script> (no frontmatter)        → Ts
51	    //   - Vue/Svelte default                     → JsModule
52	    //   - <script type="speculationrules">       → skipped (unsupported type)
53	    //   - <script type="application/ld+json">    → skipped (unsupported type)
54	    //   - <script type="text/x-handlebars-*">    → skipped (unsupported type)
55	    //
56	    // The handler dispatches on embed_match.guest to call the right parser
57	    // (parse JS vs parse JSON). No separate detector needed for JSON scripts.
58	    EmbedDetector::Element {
59	        tag: "script",
60	        target: EmbedTarget::Dynamic {
61	            resolver: resolve_script_language,
62	            // No fallback: the resolver handles all supported cases explicitly.
63	            // Returning None means "skip this element" (e.g. unsupported type
64	            // like speculationrules or application/ld+json).
65	            fallback: None,
66	        },
67	    },
68	    // <style> → CSS (dynamic: skips SCSS via resolver returning None)
69	    EmbedDetector::Element {
70	        tag: "style",
71	        target: EmbedTarget::Dynamic {
72	            resolver: resolve_style_language,
73	            // No fallback — the resolver handles all cases explicitly.
74	            // Returning None from the resolver means "skip this element."
75	            fallback: None,
76	        },
77	    },
78	    // Astro frontmatter (--- ... ---) → TypeScript
79	    // Only matches EmbedCandidate::Frontmatter, which is only built for Astro.
80	    EmbedDetector::Frontmatter {
81	        target: EmbedTarget::Static(GuestLanguage::Ts),
82	    },
83	    // Template text expressions: { expr }, {{ expr }}, {#if expr}, etc.
84	    // Guest language depends on framework:
85	    //   - Standard HTML: JsModule
86	    //   - Astro: Tsx (with Astro embedding kind)
87	    //   - Vue/Svelte: JsModule (overridden by embedded_file_source in handler)
88	    EmbedDetector::TextExpression {
89	        target: EmbedTarget::Dynamic {
90	            resolver: resolve_text_expression_language,
91	            fallback: None,
92	        },
93	    },
94	    // Directive attribute values: @click="handler()", v-if="cond",
95	    // on:click={handler}, bind:value={x}, etc.
96	    // Always JS — framework determines EmbeddingKind in handler.
97	    EmbedDetector::Directive {
98	        target: EmbedTarget::Dynamic {
99	            resolver: resolve_directive_language,
100	            fallback: None,
101	        },
102	    },
103	];
104	
105	/// Resolves the guest language for a <script> tag based on attributes and host framework.
106	/// Mirrors current logic in html.rs parse_embedded_script (978-1065).
107	fn resolve_script_language(
108	    candidate: &EmbedCandidate,
109	    file_source: &DocumentFileSource,
110	) -> Option<GuestLanguage> {
111	    let html_source = file_source.to_html_file_source()?;
112	
113	    // Check script type attribute first
114	    if let Some(type_value) = candidate.attribute("type") {
115	        let script_type = ScriptType::from_type_value(type_value.text());
116	        if script_type.is_json() {
117	            return Some(GuestLanguage::Json);
118	        }
119	        if !script_type.is_javascript() {
120	            return None; // unsupported type (e.g. text/x-handlebars-template)
121	        }
122	    }
123	
124	    // Framework-specific resolution
125	    if html_source.is_vue() || html_source.is_svelte() {
126	        // Check lang attribute
127	        if candidate.has_attribute_value("lang", "ts") {
128	            Some(GuestLanguage::Ts)
129	        } else if candidate.has_attribute_value("lang", "tsx") {
130	            Some(GuestLanguage::Tsx)
131	        } else if candidate.has_attribute_value("lang", "jsx") {
132	            Some(GuestLanguage::Jsx)
133	        } else {
134	            Some(GuestLanguage::JsModule)
135	        }
136	    } else if html_source.is_astro() {
137	        // Astro <script> tags (not frontmatter) default to TypeScript
138	        Some(GuestLanguage::Ts)
139	    } else {
140	        // Plain HTML
141	        if candidate.has_attribute_value("type", "module") {
142	            Some(GuestLanguage::JsModule)
143	        } else {
144	            Some(GuestLanguage::JsScript)
145	        }
146	    }
147	}
148	
149	fn resolve_style_language(
150	    candidate: &EmbedCandidate,
151	    _file_source: &DocumentFileSource,
152	) -> Option<GuestLanguage> {
153	    // SCSS is not supported — return None to skip this element
154	    if candidate.has_attribute_value("lang", "scss") {
155	        None
156	    } else {
157	        Some(GuestLanguage::Css)
158	    }
159	}
160	
161	/// Resolves the guest language for template text expressions.
162	/// Astro expressions use TSX; everything else uses JsModule as a base
163	/// (the handler overrides with `embedded_file_source` for Vue/Svelte).
164	fn resolve_text_expression_language(
165	    _candidate: &EmbedCandidate,
166	    file_source: &DocumentFileSource,
167	) -> Option<GuestLanguage> {
168	    let html_source = file_source.to_html_file_source()?;
169	    if html_source.is_astro() {
170	        Some(GuestLanguage::Tsx)
171	    } else {
172	        Some(GuestLanguage::JsModule)
173	    }
174	}
175	
176	/// Resolves the guest language for directive attribute values.
177	/// Always JS — the handler applies framework-specific EmbeddingKind.
178	fn resolve_directive_language(
179	    _candidate: &EmbedCandidate,
180	    _file_source: &DocumentFileSource,
181	) -> Option<GuestLanguage> {
182	    Some(GuestLanguage::JsModule)
