464	    ///
465	    /// If the syntax is SCSS-exclusive and does not overlap with CSS parsing,
466	    /// prefer [`Self::is_scss_exclusive_syntax_allowed`] instead. This helper
467	    /// is intentionally stricter because it means the caller is committing to
468	    /// SCSS semantics for ambiguous syntax.
469	    #[inline]
470	    pub(crate) const fn is_full_scss_parsing_allowed(self) -> bool {
471	        matches!(self.scss_capability(), ScssCapability::Full)
472	    }
473	}
474	
475	/// Parses any value while explicitly controlling whether SCSS-only branches are allowed.
476	#[inline]
477	pub(crate) fn parse_any_value_with_mode(p: &mut CssParser, mode: ValueParsingMode) -> ParsedSyntax {
478	    parse_any_value_with_context(p, ValueParsingContext::new(p, mode))
479	}
480	
481	#[inline]
482	pub(crate) fn parse_any_value_with_context(
483	    p: &mut CssParser,
484	    context: ValueParsingContext,
485	) -> ParsedSyntax {
486	    if context.is_scss_exclusive_syntax_allowed() && is_at_any_scss_value(p) {
487	        parse_any_exclusive_scss_value(p)
488	    } else if is_at_any_css_function(p) {
489	        // CSS functions stay on this branch. SCSS-only function heads
490	        // (`namespace.fn(...)`, interpolation-led heads, etc.) are claimed above
491	        // so CSS mode still rejects them while SCSS mode parses them as functions.
492	        parse_any_function_with_context(p, context)
493	    } else {
494	        parse_any_non_function_css_value(p)
495	    }
496	}
497	
498	#[inline]
499	fn parse_any_exclusive_scss_value(p: &mut CssParser) -> ParsedSyntax {
500	    if is_at_scss_function(p) && !p.nth_at(2, T![$]) {
501	        CssSyntaxFeatures::Scss.parse_exclusive_syntax(p, parse_scss_function, |p, m| {
502	            scss_only_syntax_error(p, "SCSS qualified function names", m.range(p))
503	        })
504	    } else if is_at_scss_identifier(p) {
505	        CssSyntaxFeatures::Scss.parse_exclusive_syntax(p, parse_scss_identifier, |p, m| {
506	            scss_only_syntax_error(p, "SCSS variables", m.range(p))
507	        })
508	    } else if is_at_scss_qualified_name(p) {
509	        let has_dollar_member = p.nth_at(2, T![$]);
510	        CssSyntaxFeatures::Scss
511	            .parse_exclusive_syntax(p, parse_scss_qualified_name, |p, m| {
512	                scss_only_syntax_error(p, "SCSS qualified names", m.range(p))
513	            })
514	            .map(|marker| {
515	                add_scss_variable_member_function_name_diagnostic(p, has_dollar_member, marker)
516	            })
517	    } else if is_at_scss_interpolated_function_or_value(p) {
518	        CssSyntaxFeatures::Scss.parse_exclusive_syntax(
519	            p,
520	            parse_scss_interpolated_function_or_value,
521	            |p, m| scss_only_syntax_error(p, "SCSS interpolated values", m.range(p)),
522	        )
523	    } else if is_at_scss_parent_selector_value(p) {
524	        parse_scss_parent_selector_value(p)
525	    } else if is_at_scss_interpolated_string(p) {
526	        parse_scss_interpolated_string(p)
527	    } else {
528	        Absent
529	    }
530	}
531	
532	#[inline]
533	fn parse_any_non_function_css_value(p: &mut CssParser) -> ParsedSyntax {
534	    if is_at_dashed_identifier(p) {
535	        if p.nth_at(1, T![-]) && p.nth_at(2, T![*]) {
536	            CssSyntaxFeatures::Tailwind.parse_exclusive_syntax(
537	                p,
538	                parse_tailwind_value_theme_reference,
539	                |p, m| tailwind_disabled(p, m.range(p)),
540	            )
541	        } else {
542	            parse_dashed_identifier(p)
543	        }
544	    } else if is_at_unicode_range(p) {
545	        parse_unicode_range(p)
546	    } else if is_at_identifier(p) {
547	        parse_regular_identifier(p)
548	    } else if p.at(CSS_STRING_LITERAL) {
549	        parse_string(p)
550	    } else if is_at_any_dimension(p) {
551	        parse_any_dimension(p)
552	    } else if is_at_ratio(p) {
553	        parse_ratio(p)
554	    } else if p.at(CSS_NUMBER_LITERAL) {
555	        parse_regular_number(p)
556	    } else if is_at_color(p) {
557	        parse_color(p)
558	    } else if is_at_bracketed_value(p) {
559	        parse_bracketed_value(p)
560	    } else if is_at_metavariable(p) {
561	        parse_metavariable(p)
562	    } else {
563	        Absent
564	    }
565	}
