567	#[inline]
568	pub(crate) fn is_at_ratio(p: &mut CssParser) -> bool {
569	    p.at(CSS_NUMBER_LITERAL) && p.nth_at(1, T![/]) && p.nth_at(2, CSS_NUMBER_LITERAL)
570	}
571	
572	#[inline]
573	pub(crate) fn parse_ratio(p: &mut CssParser) -> ParsedSyntax {
574	    if !is_at_ratio(p) {
575	        return Absent;
576	    }
577	    let m = p.start();
578	    parse_regular_number(p).ok();
579	    p.bump(T![/]);
580	    parse_regular_number(p).ok();
581	    Present(m.complete(p, CSS_RATIO))
582	}
