584	#[inline]
585	pub(crate) fn is_at_css_wide_keyword(p: &mut CssParser) -> bool {
586	    p.cur().is_css_wide_keyword()
587	}
588	
589	#[inline]
590	pub(crate) fn is_at_identifier(p: &mut CssParser) -> bool {
591	    is_nth_at_identifier(p, 0)
592	}
593	
594	#[inline]
595	pub(crate) fn is_nth_at_identifier(p: &mut CssParser, n: usize) -> bool {
596	    p.nth_at(n, T![ident]) || p.nth(n).is_contextual_keyword()
597	}
