599	/// Parse any identifier using the Regular lexing context.
600	#[inline]
601	pub(crate) fn parse_regular_identifier(p: &mut CssParser) -> ParsedSyntax {
602	    parse_identifier(p, CssLexContext::Regular)
603	}
604	
605	/// Parse any identifier as a general CssIdentifier. Regular identifiers are
606	/// case-insensitive, often used for property names, values, etc.
607	#[inline]
608	pub(crate) fn parse_identifier(p: &mut CssParser, context: CssLexContext) -> ParsedSyntax {
609	    if !is_at_identifier(p) {
610	        return Absent;
611	    }
612	
613	    let m = p.start();
614	    p.bump_remap_with_context(T![ident], context);
615	    let identifier = m.complete(p, CSS_IDENTIFIER);
616	
617	    Present(identifier)
618	}
619	
620	/// Custom identifiers are identifiers not defined by CSS itself. These _are_
621	/// case-sensitive, used for class names, ids, etc. Custom identifiers _may_
622	/// have the same value as an identifier defined by CSS (e.g, `color`, used as
623	/// a class name), however they _must not_ be any of the CSS-wide keywords.
624	///
625	/// Custom identifiers have the same syntax as general identifiers, so the
626	/// [is_at_identifier] function can be used to check for both while parsing.
627	///
628	/// Custom identifiers can also be used in places where the CSS grammar
629	/// specifies `<ident>` but also includes case-sensitivity, such as in
630	/// class and id selectors. In these cases, CSS wide keywords _are_ accepted,
631	/// and can be handled by calling `parse_custom_identifier_with_keywords` with
632	/// `allow_css_wide_keywords` as `true` to cast them as identifiers.
633	///
634	/// When recovering from a parse error here, use
635	/// [parse_error::expected_non_css_wide_keyword_identifier] to provide the user
636	/// with additional information about how the CSS-wide keywords are not allowed
637	/// as custom identifiers.
638	#[inline]
639	pub(crate) fn parse_custom_identifier(p: &mut CssParser, context: CssLexContext) -> ParsedSyntax {
640	    parse_custom_identifier_with_keywords(p, context, false)
641	}
642	
643	/// See [parse_custom_identifier]. This function allows for overriding the
644	/// handling of CSS-wide keywords using the `allow_css_wide_keywords` parameter.
645	///
646	/// This function should only be needed in cases where the CSS specification
647	/// defines a token as `<ident>` _and also_ case-sensitive. Otherwise, either
648	/// `parse_identifier` or `parse_custom_identifier` should be sufficient.
649	#[inline]
650	pub(crate) fn parse_custom_identifier_with_keywords(
651	    p: &mut CssParser,
652	    context: CssLexContext,
653	    allow_css_wide_keywords: bool,
654	) -> ParsedSyntax {
655	    if !is_at_identifier(p) || (!allow_css_wide_keywords && is_at_css_wide_keyword(p)) {
656	        return Absent;
657	    }
658	
659	    let m = p.start();
660	    p.bump_remap_with_context(T![ident], context);
661	    let identifier = m.complete(p, CSS_CUSTOM_IDENTIFIER);
662	
663	    Present(identifier)
664	}
