671	/// Dashed identifiers are any identifiers that start with two dashes (`--`).
672	/// Case sensitive, these are guaranteed to never overlap with an identifier
673	/// defined by CSS.
674	#[inline]
675	pub(crate) fn parse_dashed_identifier(p: &mut CssParser) -> ParsedSyntax {
676	    if !is_at_dashed_identifier(p) {
677	        return Absent;
678	    }
679	
680	    let m = p.start();
681	    p.bump(T![ident]);
682	    Present(m.complete(p, CSS_DASHED_IDENTIFIER))
683	}
