690	pub(crate) fn parse_number(p: &mut CssParser, context: CssLexContext) -> ParsedSyntax {
691	    if !p.at(CSS_NUMBER_LITERAL) {
692	        return Absent;
693	    }
694	
695	    let m = p.start();
696	
697	    p.bump_with_context(CSS_NUMBER_LITERAL, context);
