702	#[inline]
703	pub(crate) fn parse_string(p: &mut CssParser) -> ParsedSyntax {
704	    if !is_at_string(p) {
705	        return Absent;
706	    }
707	
708	    let m = p.start();
709	
710	    p.bump(CSS_STRING_LITERAL);
711	
712	    Present(m.complete(p, CSS_STRING))
713	}
