720	/// Checks if the parser is currently at the start of a bracketed value.
721	#[inline]
722	pub(crate) fn is_at_bracketed_value(p: &mut CssParser) -> bool {
723	    p.at(T!['['])
724	}
725	
726	/// Parses a bracketed value from the current position in the CSS parser.
727	///
728	/// This function parses a list of values enclosed in square brackets, commonly used in CSS properties
729	/// like `grid-template-areas` where the value is a list of identifiers representing grid areas.
730	/// For details on the syntax of bracketed values,
731	/// see the [CSS Syntax specification](https://drafts.csswg.org/css-grid/#named-lines)
732	#[inline]
733	pub(crate) fn parse_bracketed_value(p: &mut CssParser) -> ParsedSyntax {
734	    if !is_at_bracketed_value(p) {
735	        return Absent;
736	    }
737	
738	    let m = p.start();
739	
740	    p.bump(T!['[']);
741	    BracketedValueList::default().parse_list(p);
742	    p.expect(T![']']);
743	
744	    Present(m.complete(p, CSS_BRACKETED_VALUE))
745	}
746	
747	/// The list parser for bracketed values.
748	///
749	/// This parser is responsible for parsing a list of identifiers inside a bracketed value.
750	#[derive(Default)]
751	pub(crate) struct BracketedValueList {
752	    separator: Option<BracketedValueSeparator>,
753	    mixed_separators_reported: bool,
754	}
755	
756	#[derive(Copy, Clone, Eq, PartialEq)]
757	enum BracketedValueSeparator {
758	    Comma,
759	    Slash,
760	}
761	
762	impl BracketedValueSeparator {
763	    fn from_current_token(p: &mut CssParser) -> Option<Self> {
764	        if p.at(T![,]) {
765	            Some(Self::Comma)
766	        } else if p.at(T![/]) {
767	            Some(Self::Slash)
768	        } else {
769	            None
770	        }
771	    }
772	
773	    fn bump(self, p: &mut CssParser) {
774	        match self {
775	            Self::Comma => p.bump(T![,]),
776	            Self::Slash => p.bump(T![/]),
777	        }
778	    }
779	
780	    fn as_str(self) -> &'static str {
781	        match self {
782	            Self::Comma => "`,`",
783	            Self::Slash => "`/`",
784	        }
785	    }
786	}
787	
788	impl ParseNodeList for BracketedValueList {
789	    type Kind = CssSyntaxKind;
790	    type Parser<'source> = CssParser<'source>;
791	    const LIST_KIND: Self::Kind = CSS_BRACKETED_VALUE_LIST;
792	
793	    fn parse_element(&mut self, p: &mut Self::Parser<'_>) -> ParsedSyntax {
794	        if p.at(T![*]) {
795	            return CssSyntaxFeatures::Tailwind.parse_exclusive_syntax(
796	                p,
797	                |p| {
798	                    let m = p.start();
799	                    p.bump_remap(T![ident]);
800	                    Present(m.complete(p, CSS_CUSTOM_IDENTIFIER))
801	                },
802	                |p, m| tailwind_disabled(p, m.range(p)),
803	            );
804	        }
805	
806	        if let Some(separator) = BracketedValueSeparator::from_current_token(p) {
807	            return self.parse_scss_bracketed_value_delimiter(p, separator);
808	        }
809	
810	        parse_custom_identifier(p, CssLexContext::Regular)
811	    }
812	
813	    fn is_at_list_end(&self, p: &mut Self::Parser<'_>) -> bool {
814	        p.at(T![']'])
815	    }
816	
817	    fn recover(
818	        &mut self,
819	        p: &mut Self::Parser<'_>,
820	        parsed_element: ParsedSyntax,
821	    ) -> RecoveryResult {
822	        parsed_element.or_recover(
823	            p,
824	            &BracketedValueListRecovery,
825	            expected_non_css_wide_keyword_identifier,
826	        )
827	    }
828	}
829	
830	impl BracketedValueList {
831	    fn parse_scss_bracketed_value_delimiter(
832	        &mut self,
833	        p: &mut CssParser,
834	        separator: BracketedValueSeparator,
835	    ) -> ParsedSyntax {
836	        // Preserve explicit separators inside bracketed values so Sass list
837	        // separators survive parsing (e.g. `[a, b, c]`).
838	        // Example: `$list: [a, b, c];`
839	        // Docs: https://sass-lang.com/documentation/values/lists
840	        CssSyntaxFeatures::Scss.parse_exclusive_syntax(
841	            p,
842	            |p| {
843	                let m = p.start();
844	                self.report_mixed_separator_if_needed(p, separator);
845	                separator.bump(p);
846	                Present(m.complete(p, CSS_GENERIC_DELIMITER))
847	            },
848	            |p, m| scss_only_syntax_error(p, "Sass list separators", m.range(p)),
849	        )
850	    }
851	
852	    fn report_mixed_separator_if_needed(
853	        &mut self,
854	        p: &mut CssParser,
855	        separator: BracketedValueSeparator,
856	    ) {
857	        let Some(previous_separator) = self.separator else {
858	            self.separator = Some(separator);
859	            return;
860	        };
861	
862	        if previous_separator != separator && !self.mixed_separators_reported {
863	            p.error(inconsistent_scss_bracketed_list_separators(
864	                p,
865	                previous_separator.as_str(),
866	                separator.as_str(),
867	                p.cur_range(),
868	            ));
869	            self.mixed_separators_reported = true;
870	        }
871	    }
872	}
