874	/// Recovery strategy for bracketed value lists.
875	///
876	/// This recovery strategy handles the recovery process when parsing bracketed value lists.
877	struct BracketedValueListRecovery;
878	
879	impl ParseRecovery for BracketedValueListRecovery {
880	    type Kind = CssSyntaxKind;
881	    type Parser<'source> = CssParser<'source>;
882	    const RECOVERED_KIND: Self::Kind = CSS_BOGUS_CUSTOM_IDENTIFIER;
883	
884	    fn is_at_recovered(&self, p: &mut Self::Parser<'_>) -> bool {
885	        // If the next token is the end of the list or the next element, we're at a recovery point.
886	        p.at(T![']'])
887	            || is_at_identifier(p)
888	            || (CssSyntaxFeatures::Scss.is_supported(p) && (p.at(T![,]) || p.at(T![/])))
889	    }
890	}
