892	/// Attempt to parse some input with the given parsing function. If parsing
893	/// succeeds, `Ok` is returned with the result of the parse and the state is
894	/// preserved. If parsing fails, this function rewinds the parser back to
895	/// where it was before attempting the parse and the `Err` value is returned.
896	#[must_use = "The result of try_parse contains information about whether the parse succeeded and should not be ignored"]
897	pub(crate) fn try_parse<T, E>(
898	    p: &mut CssParser,
899	    func: impl FnOnce(&mut CssParser) -> Result<T, E>,
900	) -> Result<T, E> {
901	    let checkpoint = p.checkpoint();
902	    let old_speculative_parsing = std::mem::replace(&mut p.state_mut().speculative_parsing, true);
903	
904	    let res = func(p);
905	    p.state_mut().speculative_parsing = old_speculative_parsing;
906	
907	    if res.is_err() {
908	        p.rewind(checkpoint);
909	    }
910	
911	    res
912	}
