914	#[cfg(test)]
915	mod tests {
916	    use crate::{CssParserOptions, parser::CssParser};
917	    use biome_css_syntax::{CssFileSource, CssSyntaxKind, T};
918	    use biome_parser::Parser;
919	    use biome_parser::prelude::ParsedSyntax::{Absent, Present};
920	
921	    use super::{parse_regular_identifier, parse_regular_number, try_parse};
922	
923	    #[test]
924	    fn try_parse_rewinds_to_checkpoint() {
925	        let mut p = CssParser::new(
926	            "width: blue;",
927	            CssFileSource::css(),
928	            CssParserOptions::default(),
929	        );
930	
931	        let pre_try_range = p.cur_range();
932	        let result = try_parse(&mut p, |p| {
933	            // advance the parser within the attempt
934	            // parse `width`
935	            parse_regular_identifier(p).ok();
936	            // parse `:`
937	            p.expect(T![:]);
938	
939	            // attempt to parse a number, but fail because the input has `blue`.
940	            match parse_regular_number(p) {
941	                Present(marker) => Ok(Present(marker)),
942	                Absent => Err(()),
943	            }
944	        });
945	
946	        assert!(result.is_err());
947	        // The parser should've rewound back to the start.
948	        assert_eq!(p.cur_range(), pre_try_range);
949	        assert_eq!(p.cur_text(), "width");
950	    }
951	
952	    #[test]
953	    fn try_parse_preserves_position_on_success() {
954	        let mut p = CssParser::new(
955	            "width: 100;",
956	            CssFileSource::css(),
957	            CssParserOptions::default(),
958	        );
959	
960	        let pre_try_range = p.cur_range();
961	        let result = try_parse(&mut p, |p| {
962	            // advance the parser within the attempt
963	            // parse `width`
964	            parse_regular_identifier(p).ok();
965	            // parse `:`
966	            p.expect(T![:]);
967	
968	            // attempt to parse a number, and succeed because the input has `100`.
969	            match parse_regular_number(p) {
970	                Present(marker) => Ok(Present(marker)),
971	                Absent => Err(()),
972	            }
973	        });
974	
975	        assert!(result.is_ok());
976	        assert_eq!(result.unwrap().kind(&p), Some(CssSyntaxKind::CSS_NUMBER));
977	        // The parser should not have rewound and is now at the semicolon
978	        assert_ne!(p.cur_range(), pre_try_range);
979	        assert_eq!(p.cur_text(), ";");
980	    }
981	}
