4	
5	#[ignore]
6	#[test]
7	pub fn quick_test() {
8	    let code = r#"
9	  .card {
10	    label:hover {
11	      color: red;
12	    }
13	  }
14	"#;
15	
16	    let root = parse_css(
17	        code,
18	        CssFileSource::scss(),
19	        CssParserOptions::default()
20	            .allow_wrong_line_comments()
21	            .allow_css_modules()
22	            .allow_metavariables()
23	            .allow_tailwind_directives(),
