use biome_css_parser::{CssParserOptions, parse_css};
use biome_css_syntax::{CssFileSource, EmbeddingKind};
use biome_test_utils::has_bogus_nodes_or_empty_slots;

#[test]
pub fn quick_test() {
    // Test that property:value pairs with { after the colon are parsed as
    // nested rules, not declarations
    let code = r#"div:first-of-type {
    color: black;
  }
  background: black;"#;

    let root = parse_css(
        code,
        CssFileSource::css().with_embedding_kind(EmbeddingKind::Styled),
        CssParserOptions::default(),
    );
    let syntax = root.syntax();
    dbg!(&syntax, root.diagnostics(), root.has_errors());
    if has_bogus_nodes_or_empty_slots(&syntax) {
        panic!("modified tree has bogus nodes or empty slots:\n{syntax:#?} \n\n {syntax}")
    }
    assert!(!root.has_errors(), "Expected no parse errors");
}

#[test]
pub fn quick_test2() {
    // Test minimal nesting case
    let code = r#".foo {
    & td {
        &.c { color: red }
    }
}"#;

    let root = parse_css(
        code,
        CssFileSource::css(),
        CssParserOptions::default(),
    );
    let syntax = root.syntax();
    dbg!(&syntax, root.diagnostics(), root.has_errors());
    if has_bogus_nodes_or_empty_slots(&syntax) {
        panic!("modified tree has bogus nodes or empty slots:\n{syntax:#?} \n\n {syntax}")
    }
    assert!(!root.has_errors(), "Expected no parse errors");
}

