/// }
///
/// .alert {
///     composes: alertText;
/// }
/// ```
fn parse_composes_property_with_value_end_set(
    p: &mut CssParser,
    value_end_set: TokenSet<CssSyntaxKind>,
    recovery_end_set: TokenSet<CssSyntaxKind>,
) -> ParsedSyntax {
    if !is_at_composes_property(p) {
        return Absent;
