    type Parser<'source> = CssParser<'source>;
    const LIST_KIND: Self::Kind = CSS_GENERIC_COMPONENT_VALUE_LIST;

    fn parse_element(&mut self, p: &mut Self::Parser<'_>) -> ParsedSyntax {
        eprintln!("DEBUG GCVL: parse_element at '{}'", p.cur_text());
        parse_generic_component_value(p)
    }

    fn is_at_list_end(&self, p: &mut Self::Parser<'_>) -> bool {
        let result = p.at_ts(self.end_set) || self.at_boundary(p);
        eprintln!("DEBUG GCVL: is_at_list_end at '{}' -> {}", p.cur_text(), result);
        result
    }

    fn recover(
        &mut self,
        p: &mut Self::Parser<'_>,
        parsed_element: ParsedSyntax,
    ) -> RecoveryResult {
        if self.at_boundary(p) {
            return Err(RecoveryError::AlreadyRecovered);
        }

        // Track if we encounter a curly brace during declaration value parsing.
        // This is used by speculative declaration parsing in
        // `DeclarationOrRuleList::parse_element` to reject declarations that
        // accidentally consume rule-block tokens (e.g. `div:first-of-type { ... }`).
        // Only set the flag when the element is actually absent (recovery will
        // consume the token), not when the element was successfully parsed and
        // the parser is merely positioned at a curly brace.
        if parsed_element.is_absent() && (p.at(T!['{']) || p.at(T!['}'])) {
            p.state_mut().encountered_curly_brace_in_value = true;
        }

        parsed_element.or_recover_with_token_set(
            p,
            &ParseRecoveryTokenSet::new(CSS_BOGUS_PROPERTY_VALUE, self.recovery_set)
                .enable_recovery_on_line_break(),
            expected_component_value,
        )
    }
}

#[inline]
pub(crate) fn is_at_generic_component_value(p: &mut CssParser) -> bool {
    is_at_any_value(p) || is_at_generic_delimiter(p)
}

#[inline]
pub(crate) fn parse_generic_component_value(p: &mut CssParser) -> ParsedSyntax {
    if !is_at_generic_component_value(p) {
        return Absent;
    }

    if is_at_generic_delimiter(p) {
        parse_generic_delimiter(p)
    } else {
        parse_any_value(p)
    }
}

const GENERIC_DELIMITER_SET: TokenSet<CssSyntaxKind> = token_set![T![,], T![/]];
#[inline]
pub(crate) fn is_at_generic_delimiter(p: &mut CssParser) -> bool {
    p.at_ts(GENERIC_DELIMITER_SET)
}

#[inline]
fn parse_generic_delimiter(p: &mut CssParser) -> ParsedSyntax {
    if !is_at_generic_delimiter(p) {
        return Absent;
    }

    let m = p.start();
    p.bump_ts(GENERIC_DELIMITER_SET);
    Present(m.complete(p, CSS_GENERIC_DELIMITER))
}

